+    // For boolean OR reductions (i1 type), ensure that all reduced values are
+    // guaranteed not to be poison, otherwise the vector reduction may incorrectly
+    // propagate poison. This is because logical OR reductions via select patterns
+    // can mask poison, but vector.reduce.or does not.
+    if (RdxKind == RecurKind::Or) {
+      bool HasBoolType = false;
+      for (ArrayRef<Value *> RV : ReducedVals) {
+        for (Value *V : RV) {
+          if (V->getType()->isIntegerTy(1)) {
+            HasBoolType = true;
+            if (!isGuaranteedNotToBePoison(V))
+              return false;
+          }
+        }
+      }
+      // If there are no i1 types, we can proceed (integer OR reduction).
